            //
            aOrbiterC = ((aOrbiterC + aOrbiterD) + 0x08D17CE7B0A8BB09ULL) + aPhaseDOrbiterUpdateSaltE[((aIndex + 24U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterC) ^ 0xDF1AE4E07B045966ULL;
